// Creamos un array vacío donde acumularemos los nuevos items
const out = [];

// Recorremos cada item de entrada (normalmente 1 email por ejecución)
for (const inItem of items) {

  // Obtenemos todos los binarios del email (adjuntos)
  // Si no existe la propiedad binary, usamos un objeto vacío
  const binaries = inItem.binary ?? {};

  // Recorremos cada adjunto del email
  for (const [key, bin] of Object.entries(binaries)) {

    // Por cada adjunto generamos un item independiente
    out.push({
      json: {
        // Índice del email dentro de la ejecución (útil para debug)
        sourceEmailIndex: inItem.$index,

        // Nombre original de la key binaria (ej: attachment_0)
        originalKey: key,

        // Nombre del archivo adjunto
        fileName: bin.fileName,

        // Tipo MIME del archivo
        mimeType: bin.mimeType,

        // Tamaño del archivo
        fileSize: bin.fileSize,

        // Datos del email original que arrastramos para contexto
        subject: inItem.json?.subject,
        from: inItem.json?.from,
        date: inItem.json?.date,

        // UID real del email en IMAP
        // En tu caso viene dentro de attributes.uid
        uid: inItem.json?.attributes?.uid,

        // Message-ID del email
        // En tu caso viene dentro de metadata["message-id"]
        messageId: inItem.json?.metadata?.["message-id"],
      },

      // Renombramos el adjunto a "data"
      // para que los siguientes nodos lo puedan usar de forma estándar
      binary: {
        data: bin,
      },
    });
  }
}

// Devolvemos un item por cada adjunto encontrado
return out;

// Ordenar poniendo PDFs primero
const sorted = items.sort((a, b) => {
  const aIsPdf = (a.json.mimeType || '').includes('application/pdf');
  const bIsPdf = (b.json.mimeType || '').includes('application/pdf');
  if (aIsPdf && !bIsPdf) return -1;
  if (!aIsPdf && bIsPdf) return 1;
  return 0;
});

// Devolver solo el primero
return [sorted[0]];

