const WP_API_URL = "https://www.corresponsables.com/wp-json/wp/v2";
const USER = "noticias@corresponsables.com";
const APP_PASSWORD = "TlRg KQVP j6g6 UnLB fEWG ggCm";
const POST_ID = $('Create a Post').first().json.id;
const rawTags = $('Get a record').first().json['Etiquetas'] ?? '';
const tagsToAssign = rawTags.split('|').map(t => t.trim()).filter(t => t.length > 0);

if (tagsToAssign.length === 0) {
  return [{ json: { message: 'Sin etiquetas, nada que asignar.' } }];
}

async function ensureTagExists(tagName) {
  // 1. Buscar si ya existe
  const search = await this.helpers.httpRequest({
    method: "GET",
    url: `${WP_API_URL}/tags`,
    qs: { search: tagName },
    auth: { username: USER, password: APP_PASSWORD },
    json: true
  });

  if (Array.isArray(search) && search.length > 0) {
    const exact = search.find(t => t.name.toLowerCase() === tagName.toLowerCase());
    if (exact) return { id: exact.id, name: exact.name };
  }

  // 2. Intentar crear — capturamos term_exists con ignoreHttpStatusErrors
  const res = await this.helpers.httpRequest({
    method: "POST",
    url: `${WP_API_URL}/tags`,
    body: { name: tagName },
    auth: { username: USER, password: APP_PASSWORD },
    json: true,
    ignoreHttpStatusErrors: true
  });

  if (res.code === 'term_exists') {
    return { id: res.data.term_id, name: tagName };
  }

  return { id: res.id, name: res.name };
}

async function run() {
  const tagObjects = [];

  for (const tagName of tagsToAssign) {
    const tag = await ensureTagExists(tagName);
    tagObjects.push(tag);
  }

  const tagIds = tagObjects.map(t => t.id);

  await this.helpers.httpRequest({
    method: "POST",
    url: `${WP_API_URL}/posts/${POST_ID}`,
    body: { tags: tagIds },
    auth: { username: USER, password: APP_PASSWORD },
    json: true
  });

  return [{ json: { success: true, tags: tagObjects } }];
}

return run();

