// Get a record con downloadFields devuelve la imagen con una clave dinámica
// (ej: "Imagen WP_0"). La renombramos a 'data' para que Upload IMG to WP Media la encuentre.
const item = items[0];
const binaries = item.binary ?? {};

// Buscar la primera clave que contenga imagen
const imgKey = Object.keys(binaries).find(k => 
  binaries[k].mimeType?.startsWith('image/') || k.toLowerCase().includes('imagen')
) ?? Object.keys(binaries)[0];

if (!imgKey) {
  throw new Error('No se encontró imagen binaria en el item de Airtable');
}

return [{
  json: {
    ...item.json,
    _imgFileName: binaries[imgKey].fileName,
    _imgMimeType: binaries[imgKey].mimeType,
  },
  binary: {
    data: binaries[imgKey]  // renombrar a 'data'
  }
}];
